  try { return JSON.parse(value); } catch {}
  const stripped = value.replace(/```(?:json)?\s*|\s*```/g, '').trim();
  try { return JSON.parse(stripped); } catch {}
  const fenced = value.match(/\{[\s\S]*\}/);
  if (fenced) { try { return JSON.parse(fenced[0]); } catch {} }
  return null;
}
function normalize(parsed) {
  if (!parsed || typeof parsed !== 'object') return null;
  const leadScoreRaw = parsed.lead_score ?? parsed.leadScore ?? parsed.score;
  const reasonRaw = parsed.reason ?? parsed.justification ?? parsed.rationale;
  const leadScore = Number(leadScoreRaw);
  return {
    lead_score: Number.isFinite(leadScore) ? Math.max(1, Math.min(10, leadScore)) : undefined,
    reason: reasonRaw === undefined || reasonRaw === null ? '' : String(reasonRaw).trim()
  };
}
const normalized = normalize(extractJSON(raw));
const required = ["lead_score","reason"];
const missing = required.filter((key) => normalized?.[key] === undefined || normalized?.[key] === null || normalized?.[key] === '');
const ok = !!normalized && missing.length === 0;
const base = $input.first().json;
const retryCount = Number(base.qualifier_retry_count || 0);
return [{ json: { ...base, qualification: ok ? normalized : {}, qualifier_retry_count: retryCount, _ok: ok, _agent: 'qualifier', _required: required, _missing: missing, _raw: ok ? undefined : String(raw || JSON.stringify(response)).substring(0, 1000) } }];

const failed = (typeof $json === 'object' && $json !== null) ? $json : {};
const retryCount = Number(failed.qualifier_retry_count || 0) + 1;
const maxRetries = Math.max(0, Number($env.QUALIFIER_MAX_RETRIES || 0));
const responseText = String(failed._raw || '').toLowerCase();
const looksTransient = responseText.includes('timeout') || responseText.includes('429') || responseText.includes('502') || responseText.includes('503') || responseText.includes('504');
const shouldRetry = !failed._ok && looksTransient && retryCount <= maxRetries;
if (shouldRetry) {
  return { json: { ...failed, qualifier_retry_count: retryCount, _retry: true, _retry_stage: 'qualifier' } };
}
const fallback = {
  lead_score: failed.classification?.type === 'sales_inquiry' ? 7 : 4,
  reason: 'Fallback qualification used after qualifier retries were exhausted.'
};
const hasQualification = failed.qualification?.lead_score !== undefined && failed.qualification?.reason;
const output = {
  ...failed,
  qualification: hasQualification ? failed.qualification : fallback,
  qualifier_retry_count: retryCount,
  _ok: true,
  _retry: false,
  _agent: hasQualification ? failed._agent : 'qualifier_fallback',
  _missing: [],
  _required: ['lead_score', 'reason'],
  _raw: hasQualification ? failed._raw : undefined
};
return { json: output };

